var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그만해요! 에델을 고슴도치로 만들 셈인가요?!","JPN":"そ、それくらいにしてください！　エデルをハリネズミにするつもりですの！？","ENG":"S-stop! You're going to kill her!","TWN":"住，住手！妳想把艾瑟兒釘成刺蝟嗎？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"걱정 마. 비주얼이 좀 끔찍하긴 하지만 에델은 이 정도론 안 죽어.","JPN":"心配いらないよ。見た目はちょっとアレだけど、エデルはこのくらいじゃ死なないから。","ENG":"Don't worry. As awful as it may look, Edel won't die from this.","TWN":"別擔心。雖然視覺上有點可怕，但艾瑟兒不會因為這種程度死掉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델은 대식가라서 말이야. 가끔 허기로 맛이 가면 말려 줄 사람이 필요해.","JPN":"エデルは大喰らいだからさ。時々お腹が空きすぎて正気を失ったら、止めてあげる人が必要なの。","ENG":"Edel is a very enthusiastic binge eater. When she gets too hungry and loses it, someone has to stop her.","TWN":"艾瑟兒是個大胃王啊。她有時會因為饑餓發狂，所以需要有人阻止她。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그럴 때마다 정신이 돌아올 때까지 이 봉인주로 에델을 못박아 두는 게 내 일이거든.","JPN":"そのたびに正気に戻るまでこの封印柱でエデルを動けなくするのが、アタシの仕事なんだ。","ENG":"It's my job to nail her down with these sealing stakes until she comes to her senses.","TWN":"每次在艾瑟兒清醒過來之前，用封印槍把她釘起來就是我的工作。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이런 걸로 못박히면 사람은 죽어요!","JPN":"こんなやり方では人は死んでしまいますわ！","ENG":"No one's going to survive that much nailing-down!","TWN":"用這種東西會釘死人的！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델이 아직도 사람이라고 생각해?","JPN":"まだエデルが人だと思ってるの？","ENG":"You still think Edel is like one of us?","TWN":"妳現在還覺得艾瑟兒是人嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만...... 아니, 그 촉수들은 분명......","JPN":"でも……いや、あの触手は確かに……","ENG":"But... No, those tentacles were actually...","TWN":"但是… 不，那些觸手肯定是……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델은...... 에델은 뭐죠?","JPN":"エデルは……エデルは何者なのです？","ENG":"What... What is Edel?","TWN":"艾瑟兒……艾瑟兒究竟是什麼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"글쎄? 공포소설에 자주 나오는 촉수 달린 괴물?","JPN":"さあね。ホラー小説によく出てくる触手の怪物？","ENG":"I don't know. A tentacled monster, like the ones in horror fictions?","TWN":"誰知道？恐怖小說裡經常出現的觸手怪物？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지금 그런 오컬트 같은 황당한 소리나 할 상황이에요?!","JPN":"そんなオカルトのようなあり得ないことを言ってる場合ですか！？","ENG":"Will you stop trying to be funny with the stupid occult references?","TWN":"現在是說這種不合理超自然現象的時候嗎？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"......레지나야말로 무슨 소리야?","JPN":"……レジーナこそ、何言ってんの？","ENG":"What are you talking about?","TWN":"……蕾佳娜妳才是在說什麼呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"나 같은 용병들에겐 지금이 바로 오컬트의 시대라고.","JPN":"アタシみたいな傭兵にとって、この時代はオカルトそのものなんだけど。","ENG":"It's been some time now since this world started to look like a giant stage for occult movies, especially to mercenaries like me.","TWN":"對我這種傭兵而言，現在就是超自然的時代啊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네......?","JPN":"えっ……？","ENG":"Huh?","TWN":"什麼……?"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"다른 세상에서 괴물들이 넘어오고 사람들은 손에서 뿜어내는 불로 그 괴물들을 잡아. 그리고 괴물의 시체에서 마법의 돌을 끄집어내지.","JPN":"他の世界から怪物がやって来て、\\n人は手から放たれる炎でその怪物を倒すの。\\nそして怪物の死体から魔法の石を抉り出すんだよ。","ENG":"Monsters are invading from the other world, and there are people hunting them down, shooting fire from their palms. And they pull magic stones out of the dead monsters afterward.","TWN":"怪物從另一個世界過來，而人們從手中噴出火焰殺死它們，並且從怪物的屍體中取出魔法石頭。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"대체 어디까지가 현실이고 어디까지가 비현실이지?","JPN":"いったいどこまでが現実で、どこからが非現実なの？","ENG":"The line between fiction and reality has become blurry, Regina.","TWN":"究竟到什麼程度才是現實，到什麼程度才是非現實？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"That's...","TWN":"這個……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"용병들은 다른 건 몰라도 적응 하나는 빠른 족속들이야. 말이 되건 안되건 살아남기 위해 필요하다면 배울 준비가 되어 있지.","JPN":"傭兵って他はともかく、適応するのだけは速いんだよね。\\nあり得るかどうかはともかく、生き残るために必要なら\\n何でも身に付ける準備ができてるんだ。","ENG":"Being a mercenary means, among other things, being quick to adapt. We learn anything that's going to help with our survival, and it doesn't matter if it makes sense or not.","TWN":"當傭兵不懂其他事情，但適應速度絕對是一流的。無論像不像話，為了活下去，我們隨時都會做好學習的準備。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"지금처럼.","JPN":"今みたいにね。","ENG":"Like now.","TWN":"就像現在這樣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"으윽!!","JPN":"ううっ！！","ENG":"Ugh!","TWN":"唔啊！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델!!","JPN":"エデル！！","ENG":"Edel!","TWN":"艾瑟兒！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"하지만...... 뭐 그것도 여기까지인 것 같네.","JPN":"でも……それもここまでみたい。","ENG":"However... I'm afraid this is where it ends.","TWN":"但是……這似乎也到此為止了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그건 또 무슨 소리죠?","JPN":"それはまた、どういうことですか？","ENG":"What do you mean?","TWN":"這又是什麼意思？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델의 힘은 점점 더 강해지고 있어.","JPN":"エデルの力がどんどん強くなってる。","ENG":"Edel is getting stronger by the day.","TWN":"艾瑟兒的力量正在逐漸變強。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"조금 전에도 봤겠지만 이제 나 혼자서 에델을 막는 건 무리야.","JPN":"さっき見たと思うけど、もうアタシ一人の力でエデルを抑えられなくなってるんだ。","ENG":"As you just saw, I can't contain her on my own anymore.","TWN":"就像妳不久前看到的，現在我已經無法一個人阻止艾瑟兒了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"받은 돈이 있으니 이번 일까지는 함께 하겠지만......","JPN":"お金をもらっちゃったから、今回の仕事までは引き受けるけど……","ENG":"Payment has already been made, so I'm going to stick with her during this little excursion...","TWN":"畢竟收了錢，這次的事情我會一起處理……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"다른 뾰족한 수가 없다면 그 후에는 계약을 종료하고 떠나야겠지?","JPN":"他に手が無いなら、後は契約を終了して離れるしかないでしょ？","ENG":"But I'll have to terminate the contract and leave if I can't come up with a better way to handle this.","TWN":"但如果沒有其它好辦法，之後我應該會終止契約，然後離開吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 에델은...... 에델은 그냥 이대로 버려두겠다는 건가요?","JPN":"じゃあ、エデルは……エデルはこのまま放置するつもりですか？","ENG":"But what about Edel? Are you going to leave her like this?","TWN":"那艾瑟兒呢……妳就這樣丟下艾瑟兒了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"어라? 그 사이에 꽤 친해졌나 보네? 걱정까지 해 주고?","JPN":"あれ？　いつの間にか仲良くなったの？　心配までしちゃって。","ENG":"Huh? You seem to have grown fond of her. I'm surprised you're worried for her.","TWN":"咦？這段時間妳和她已經變得這麼要好了？甚至還會擔心她？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"글쎄, 그건 레지나 너 하기에 따라 달렸지.","JPN":"とにかく、それはレジーナ……アンタ次第だよ。","ENG":"Well, it really depends on you, Regina.","TWN":"不過，這就看蕾佳娜妳要怎麼做了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"무슨 뜻이죠?","JPN":"どういう意味ですか？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델은 학자로서도, 괴물로서도 뛰어날지 모르지만 인간으로서는 영 엉망이야.","JPN":"エデルは学者としても怪物としても優れてるかもしれないけど、人間としてはダメダメなんだよね。","ENG":"Edel may be a phenomenal scholar and a fierce monster, but she is absolutely clueless as a human being.","TWN":"艾瑟兒作為學者，作為怪物或許都很優秀，但她作為人類可是一塌糊塗。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"상식도 부족하고 낯가림도 심하지.","JPN":"常識も足りないし、人見知りも激しいしさ。","ENG":"She lacks common sense and is very fretful around strangers.","TWN":"常識不足又非常怕生。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"하지만 최근에 만난 한 사람에게는 달랐어.","JPN":"でも、最近出会ったある人に対しては違った。","ENG":"But she was acting very different around someone she had met recently.","TWN":"但最近她遇到的一個人，讓她發生了改變。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그 사람을 볼 때마다 기뻐하고 말도 귀담아 듣는 것 같았으니까.","JPN":"その人と会うたびに喜んで、話もちゃんと聞いてるみたいだったし。","ENG":"She was all smiles when this person was around, and was all ears when this person was talking to her.","TWN":"每次看到那個人她就很高興，還會仔細傾聽那個人說的話。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"심지어 허기로 제정신이 아닐 때까지.","JPN":"それも、飢えで正気を失った状態でだよ。","ENG":"And that's when she was half out of her mind from hunger.","TWN":"甚至因為饑餓發狂的時候也是。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그 사람이 누군지는...... 말하지 않아도 알겠지?","JPN":"その人っていうのが誰なのかは……言わなくてもわかるよね？","ENG":"I don't have to say who this person is, do I?","TWN":"而那個人是誰……我不說妳應該也知道吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그러니까 내 생각엔 앞으로 네가 맡아 줘야 될 역할이 있을 것 같아.","JPN":"だから、これからはアンタが担うべき役割があると思うんだ。","ENG":"So I think you're going to play a certain role for her in the future.","TWN":"所以我認為，接下來妳得在這裡工作。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"하지만...... 넌 어때, 레지나?","JPN":"でも……レジーナ、アンタはどう？","ENG":"But what about you, Regina?","TWN":"但是……妳覺得呢，蕾佳娜？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그 역할, 맡을 수 있겠어?","JPN":"その役割、背負える？","ENG":"Do you think you can take the role?","TWN":"妳能接下這份重任嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};